"""
Verwerkt 5 wijzigingen:
1. Opt-in e-mail-voorkeuren (screener + portfolio apart aan/uit-zetbaar)
2. Iets lichtere blauwe achtergrond
3. Duidelijke header-balk + prominente ('primary') knoppen
4. earnings_surprise_pct en andere ontbrekende kolommen nu correct afgerond
5. Portfolio-resultaten-tabel compacter (kleinere hoogte + kleinere tekst)

BELANGRIJK: dit vereist ook een nieuwe SQL-tabel in Supabase (user_preferences).
Draai supabase_schema.sql opnieuw in Supabase's SQL Editor (de eerdere
'create table portfolio_holdings'-regel geeft een onschuldige foutmelding
als die al bestaat -- dat is prima, negeer die en zorg dat de NIEUWE
'user_preferences'-tabel wel wordt aangemaakt).

Gebruik: python fix_preferences_and_styling.py
Draai dit vanuit je stock_screener-map.
"""
import os

FILES = {
    'dashboard.py': '"""\nDashboard: visualiseert de resultaten van screener.py en portfolio_watch.py.\n\nDit dashboard LEEST de CSV/JSON-bestanden die de andere twee scripts\nproduceren -- het haalt zelf geen nieuwe data op (behalve via de\n\'Ververs nu\'-knoppen), zodat het snel laadt.\n\nLokaal draaien:\n    streamlit run dashboard.py\n\nOp internet zetten (gratis, voor jezelf of om te delen):\n    1. Zet dit project op GitHub (in een repository)\n    2. Ga naar https://share.streamlit.io, log in met GitHub\n    3. Wijs naar je repository en dit bestand (dashboard.py)\n    4. Streamlit Cloud host \'m gratis op een publieke URL\n\nVereist: pip install -r requirements.txt (incl. streamlit)\n"""\nfrom __future__ import annotations\n\nimport json\nimport os\nfrom datetime import datetime\n\nimport pandas as pd\nimport streamlit as st\nimport yfinance as yf\n\nst.set_page_config(page_title="Trading Signalen Dashboard", page_icon="◆", layout="wide")\n\n# --- Visuele identiteit: donkere \'kluis/terminal\'-stijl, geen standaard-look ---\nst.markdown("""\n<style>\n@import url(\'https://fonts.googleapis.com/css2?family=Fraunces:opsz,wght@9..144,500;9..144,600&family=Inter:wght@400;500;600&family=IBM+Plex+Mono:wght@400;500&display=swap\');\n\nhtml, body, p, span, div, label {\n    font-family: \'Inter\', sans-serif;\n}\nh1, h2, h3 {\n    font-family: \'Fraunces\', serif !important;\n    font-weight: 600 !important;\n    letter-spacing: -0.01em;\n}\ncode, .stDataFrame, [data-testid="stMetricValue"] {\n    font-family: \'IBM Plex Mono\', monospace !important;\n}\n\n/* Het \'verzegeld\'-badge: het signatuurelement dat vertrouwelijkheid concreet maakt */\n.privacy-seal {\n    display: inline-flex;\n    align-items: center;\n    gap: 0.5rem;\n    padding: 0.35rem 0.9rem;\n    border: 1px solid #1FAE96;\n    border-radius: 999px;\n    background: rgba(31, 174, 150, 0.08);\n    font-family: \'IBM Plex Mono\', monospace;\n    font-size: 0.8rem;\n    color: #1FAE96;\n    margin-bottom: 1rem;\n}\n\n/* Zorgt dat brede tabellen horizontaal kunnen scrollen, zonder de\n   verticale hoogte/scroll van Streamlit\'s eigen tabel-weergave te\n   verstoren (vandaar: alleen deze ene laag, niet de kind-elementen) */\n[data-testid="stDataFrame"] {\n    overflow-x: auto !important;\n}\n\n/* Duidelijke header-balk: onderscheidt de titel visueel van de inhoud eronder */\n.app-header {\n    padding: 1.2rem 0 1rem 0;\n    border-bottom: 2px solid #1FAE96;\n    margin-bottom: 1.5rem;\n}\n.app-header h1 {\n    margin: 0 !important;\n}\n\n/* Iets compactere tabellen: kleinere tekst in de databladen */\n[data-testid="stDataFrame"] * {\n    font-size: 0.85rem !important;\n}\n</style>\n""", unsafe_allow_html=True)\n\n\ndef file_last_modified(path: str) -> str:\n    if not os.path.exists(path):\n        return "nooit"\n    ts = os.path.getmtime(path)\n    return datetime.fromtimestamp(ts).strftime("%Y-%m-%d %H:%M")\n\n\ndef load_screener_data():\n    if not os.path.exists("supertrend_signals.csv"):\n        return None\n    df = pd.read_csv("supertrend_signals.csv")\n    return df\n\n\ndef load_portfolio_data():\n    if not os.path.exists("portfolio_watch.csv"):\n        return None\n    df = pd.read_csv("portfolio_watch.csv")\n    return df\n\n\ndef load_portfolio_news():\n    if not os.path.exists("portfolio_watch_news.json"):\n        return {}\n    with open("portfolio_watch_news.json", encoding="utf-8") as f:\n        return json.load(f)\n\n\nst.markdown(\n    \'<div class="app-header"><h1>Trading Signalen Dashboard</h1></div>\',\n    unsafe_allow_html=True,\n)\nst.caption("Persoonlijk onderzoeksproject -- geen koopadvies. Doe altijd je eigen verdere afweging.")\n\ntab_screener, tab_portfolio = st.tabs(["Nieuwe signalen (Screener)", "Mijn Portfolio"])\n\n# ============================================================\n# TAB 1: SCREENER (publiek, geen login nodig)\n# ============================================================\nwith tab_screener:\n    col1, col2 = st.columns([3, 1])\n    with col1:\n        st.subheader("Nieuwe bullish Supertrend-signalen")\n        st.caption(f"Laatst bijgewerkt: {file_last_modified(\'supertrend_signals.csv\')}")\n    with col2:\n        run_screener = st.button("Ververs nu (duurt lang, 10-20+ min)", key="run_screener", type="primary")\n\n    if run_screener:\n        with st.spinner("Screener draait... dit kan lang duren (AEX + Nasdaq-100 + S&P 500 + DAX + CAC40)."):\n            import screener\n            screener.main()\n        st.success("Klaar! Ververs de pagina om de nieuwe resultaten te zien.")\n\n    df_screener = load_screener_data()\n    if df_screener is None or df_screener.empty:\n        st.info("Nog geen resultaten gevonden. Draai eerst \'python screener.py\', of klik hierboven op Ververs.")\n    else:\n        df_screener = df_screener.sort_values("score", ascending=False)\n\n        min_score = st.slider("Minimale score", float(df_screener["score"].min()),\n                               float(df_screener["score"].max()), float(df_screener["score"].min()))\n        filtered = df_screener[df_screener["score"] >= min_score]\n\n        format_dict = {\n            "prijs_bij_omslag": "{:.2f}", "prijs_nu": "{:.2f}",\n            "sinds_omslag_pct": "{:+.2f}%", "relatieve_sterkte": "{:+.2f}%",\n            "roic_pct": "{:+.1f}%", "score": "{:.2f}",\n            "earnings_surprise_pct": "{:+.1f}%", "afwijking_fair_value_pct": "{:+.1f}%",\n            "fair_value": "{:.2f}",\n        }\n        format_dict = {k: v for k, v in format_dict.items() if k in filtered.columns}\n\n        st.dataframe(\n            filtered.style.format(format_dict, na_rep="onbekend")\n                          .background_gradient(subset=["score"], cmap="Greens")\n                          .background_gradient(subset=["relatieve_sterkte"], cmap="RdYlGn"),\n            width="stretch",\n            height=500,\n        )\n        st.caption(f"{len(filtered)} van {len(df_screener)} signalen getoond (gefilterd op score).")\n\n# ============================================================\n# TAB 2: MIJN PORTFOLIO (persoonlijk, login vereist)\n# ============================================================\nwith tab_portfolio:\n    if not st.user.is_logged_in:\n        st.markdown(\n            \'<div class="privacy-seal">&#128274; PRIVÉ &middot; alleen zichtbaar voor jou</div>\',\n            unsafe_allow_html=True,\n        )\n        st.info("Log in om je eigen posities bij te houden. Niemand anders ziet wat je toevoegt.")\n        st.button("Inloggen met Google", on_click=st.login, type="primary")\n        st.stop()\n\n    import database\n    from portfolio_watch import check_holding\n\n    user_email = st.user.email\n    st.markdown(\n        \'<div class="privacy-seal">&#128274; PRIVÉ &middot; alleen zichtbaar voor jou</div>\',\n        unsafe_allow_html=True,\n    )\n    col1, col2 = st.columns([4, 1])\n    with col1:\n        st.subheader(f"Welkom, {st.user.name}")\n        st.caption(user_email)\n    with col2:\n        st.button("Uitloggen", on_click=st.logout)\n\n    with st.expander("E-mail-voorkeuren", expanded=False):\n        prefs = database.get_user_preferences(user_email)\n        wants_screener = st.checkbox(\n            "Wekelijkse screener-mail ontvangen (nieuwe signalen uit AEX/Nasdaq-100/S&P500/DAX/CAC40)",\n            value=prefs["wants_screener_email"],\n        )\n        wants_portfolio = st.checkbox(\n            "Wekelijkse portfolio-mail ontvangen (status + nieuws van jouw eigen posities)",\n            value=prefs["wants_portfolio_email"],\n        )\n        if st.button("Voorkeuren opslaan"):\n            database.set_user_preferences(user_email, wants_screener, wants_portfolio)\n            st.success("Voorkeuren opgeslagen!")\n\n    st.markdown("### Jouw posities")\n\n    holdings = database.get_user_holdings(user_email)\n\n    if not holdings:\n        st.info("Je hebt nog geen posities toegevoegd. Voeg hieronder je eerste toe.")\n    else:\n        for holding in holdings:\n            hcol1, hcol2, hcol3 = st.columns([3, 3, 1])\n            hcol1.write(holding["naam"])\n            hcol2.write(holding["ticker"])\n            if hcol3.button("Verwijder", key=f"delete_{holding[\'id\']}"):\n                database.delete_holding(holding["id"], user_email)\n                st.rerun()\n\n    st.markdown("**Nieuwe positie toevoegen**")\n    search_query = st.text_input(\n        "Zoek een bedrijf of crypto (bv. \'Tesla\', \'ASML\', \'Bitcoin\')", key="ticker_search"\n    )\n\n    selected_symbol = None\n    selected_name = None\n\n    if search_query:\n        try:\n            search_results = yf.Search(search_query, max_results=8).quotes\n        except Exception as exc:\n            search_results = []\n            st.caption(f"Zoeken mislukt: {exc}")\n\n        if search_results:\n            options = {}\n            for r in search_results:\n                name = r.get("shortname") or r.get("longname") or r.get("symbol")\n                label = f"{name} ({r.get(\'symbol\')}) -- {r.get(\'exchange\', \'\')}"\n                options[label] = r\n\n            chosen_label = st.selectbox("Kies de juiste match", list(options.keys()))\n            chosen = options[chosen_label]\n            selected_symbol = chosen.get("symbol")\n            selected_name = chosen.get("shortname") or chosen.get("longname") or selected_symbol\n        else:\n            st.caption("Geen resultaten gevonden voor deze zoekopdracht -- probeer een andere naam.")\n\n    if selected_symbol and st.button("Toevoegen aan mijn portfolio", type="primary"):\n        with st.spinner(f"Data controleren voor {selected_symbol}..."):\n            try:\n                test_df = yf.Ticker(selected_symbol).history(period="5d")\n            except Exception as exc:\n                test_df = None\n                st.error(f"Kon {selected_symbol} niet valideren: {exc}")\n\n        if test_df is not None and test_df.empty:\n            st.error(f"Geen recente koersdata gevonden voor {selected_symbol} -- niet toegevoegd.")\n        elif test_df is not None:\n            database.add_holding(user_email, selected_name, selected_symbol)\n            st.success(f"{selected_name} ({selected_symbol}) toegevoegd!")\n            st.rerun()\n\n    st.divider()\n\n    if holdings and st.button("Check mijn portfolio nu", key="check_my_portfolio", type="primary"):\n        with st.spinner("Bezig met checken van je posities..."):\n            results = []\n            for holding in holdings:\n                result = check_holding(holding["naam"], holding["ticker"])\n                if result:\n                    results.append(result)\n\n        if not results:\n            st.warning("Kon geen van je posities checken -- controleer of de tickers kloppen.")\n        else:\n            df_my_portfolio = pd.DataFrame(results)\n            changed = df_my_portfolio[df_my_portfolio["recent_gewijzigd"] == True]  # noqa: E712\n            if len(changed) > 0:\n                st.warning(f"{len(changed)} positie(s) recent van trend gewisseld: "\n                           + ", ".join(f"{r[\'naam\']} ({r[\'status\']})" for _, r in changed.iterrows()))\n\n            def _highlight_status(row):\n                color = "#1B3A2E" if row["status"] == "BULLISH" else (\n                    "#3A1F1D" if row["status"] == "BEARISH" else "#332B14"\n                )\n                return [f"background-color: {color}"] * len(row)\n\n            display_cols = [c for c in df_my_portfolio.columns if c != "nieuws"]\n            st.dataframe(\n                df_my_portfolio[display_cols].style.apply(_highlight_status, axis=1),\n                width="stretch",\n                height=min(38 * (len(df_my_portfolio) + 1), 300),\n            )\n\n            st.markdown("### Recent nieuws")\n            any_news = False\n            for _, row in df_my_portfolio.iterrows():\n                if row["nieuws"]:\n                    any_news = True\n                    with st.expander(f"{row[\'naam\']} ({row[\'ticker\']}) -- {len(row[\'nieuws\'])} bericht(en)"):\n                        for item in row["nieuws"]:\n                            pub_date = item["published"].strftime("%Y-%m-%d")\n                            st.markdown(f"**[{item[\'title\']}]({item[\'link\']})**  \\n"\n                                        f"*{item[\'publisher\']}, {pub_date}*")\n            if not any_news:\n                st.caption("Geen recent nieuws gevonden voor je posities.")\n\n    st.caption("Je ontvangt ook wekelijks automatisch een e-mail met deze update, "\n               "op het adres waarmee je bent ingelogd.")\n\nst.divider()\nst.caption("Dit dashboard toont technische signalen (Supertrend), fundamentele context (ROIC-schatting) "\n           "en nieuws. Het is geen geautomatiseerde strategie en geen financieel advies.")\n',
    'database.py': '"""\nDatabase-laag: leest en schrijft gebruikers-portfolio\'s in Supabase.\n\nFiltert ALTIJD op user_email in de Python-code zelf (zie supabase_schema.sql\nvoor de uitleg waarom dit hier gebeurt i.p.v. via Supabase\'s eigen\nrij-beveiliging -- we gebruiken Google-login via Streamlit, niet Supabase\'s\neigen inlogsysteem, dus die twee kunnen we niet automatisch koppelen).\n"""\nfrom __future__ import annotations\n\nimport streamlit as st\nfrom supabase import create_client, Client\n\n\n@st.cache_resource\ndef get_supabase_client() -> Client:\n    url = st.secrets["supabase"]["url"]\n    key = st.secrets["supabase"]["anon_key"]\n    return create_client(url, key)\n\n\ndef get_user_holdings(user_email: str) -> list[dict]:\n    """Geeft alle posities van deze specifieke gebruiker terug."""\n    client = get_supabase_client()\n    response = client.table("portfolio_holdings").select("*").eq("user_email", user_email).execute()\n    return response.data\n\n\ndef add_holding(user_email: str, naam: str, ticker: str) -> None:\n    """Voegt een nieuwe positie toe voor deze gebruiker."""\n    client = get_supabase_client()\n    client.table("portfolio_holdings").insert({\n        "user_email": user_email,\n        "naam": naam,\n        "ticker": ticker,\n    }).execute()\n\n\ndef delete_holding(holding_id: int, user_email: str) -> None:\n    """\n    Verwijdert een positie. Filtert OOK op user_email als extra\n    veiligheidslaag (voorkomt dat iemand een ID van een ander zou kunnen\n    raden en diens positie verwijderen).\n    """\n    client = get_supabase_client()\n    client.table("portfolio_holdings").delete().eq("id", holding_id).eq("user_email", user_email).execute()\n\n\ndef get_user_preferences(user_email: str) -> dict:\n    """\n    Geeft de e-mail-voorkeuren van deze gebruiker terug. Als er nog geen\n    rij bestaat (nieuwe gebruiker), gelden de standaardwaarden: WEL de\n    persoonlijke portfolio-mail, NIET de bredere screener-mail (opt-in).\n    """\n    client = get_supabase_client()\n    response = client.table("user_preferences").select("*").eq("user_email", user_email).execute()\n    if response.data:\n        return response.data[0]\n    return {"user_email": user_email, "wants_screener_email": False, "wants_portfolio_email": True}\n\n\ndef set_user_preferences(user_email: str, wants_screener_email: bool, wants_portfolio_email: bool) -> None:\n    """Slaat de e-mail-voorkeuren op (maakt een nieuwe rij aan, of werkt de bestaande bij)."""\n    client = get_supabase_client()\n    client.table("user_preferences").upsert({\n        "user_email": user_email,\n        "wants_screener_email": wants_screener_email,\n        "wants_portfolio_email": wants_portfolio_email,\n    }).execute()\n\n\ndef get_all_users_with_holdings() -> dict[str, list[dict]]:\n    """\n    Geeft ALLE gebruikers en hun posities terug, gegroepeerd per e-mailadres.\n    Gebruikt door het wekelijkse geplande script (niet door het dashboard\n    zelf) om iedereen een persoonlijke e-mail te kunnen sturen.\n    """\n    client = get_supabase_client()\n    response = client.table("portfolio_holdings").select("*").execute()\n\n    grouped: dict[str, list[dict]] = {}\n    for row in response.data:\n        grouped.setdefault(row["user_email"], []).append(row)\n    return grouped\n',
    'weekly_batch.py': '"""\nWekelijks batch-script: draait de gedeelde screener EN stuurt elke\ngeregistreerde gebruiker een persoonlijke e-mail over hun eigen portfolio.\n\nBedoeld om te draaien via GitHub Actions (dus GEEN Streamlit-context --\nleest configuratie via omgevingsvariabelen, niet via st.secrets zoals\nhet dashboard zelf doet).\n\nBenodigde omgevingsvariabelen (als GitHub Actions secrets, of lokaal in .env):\n  SUPABASE_URL, SUPABASE_ANON_KEY\n  EMAIL_SMTP_SERVER, EMAIL_SMTP_PORT, EMAIL_ADDRESS, EMAIL_APP_PASSWORD\n\nGebruik: python weekly_batch.py\n"""\nfrom __future__ import annotations\n\nimport os\n\nimport pandas as pd\nfrom dotenv import load_dotenv\nfrom supabase import create_client\n\nload_dotenv()\n\nimport screener\nfrom portfolio_watch import check_holding, build_email_body\nfrom emailer import send_email\n\n\ndef get_supabase_client():\n    url = os.environ["SUPABASE_URL"]\n    key = os.environ["SUPABASE_ANON_KEY"]\n    return create_client(url, key)\n\n\ndef get_all_users_with_holdings() -> dict:\n    """Geeft alle gebruikers en hun posities terug, gegroepeerd per e-mailadres."""\n    client = get_supabase_client()\n    response = client.table("portfolio_holdings").select("*").execute()\n\n    grouped: dict[str, list[dict]] = {}\n    for row in response.data:\n        grouped.setdefault(row["user_email"], []).append(row)\n    return grouped\n\n\ndef get_all_preferences() -> dict:\n    """Geeft de e-mail-voorkeuren van ALLE gebruikers terug die ooit iets hebben ingesteld."""\n    client = get_supabase_client()\n    response = client.table("user_preferences").select("*").execute()\n    return {row["user_email"]: row for row in response.data}\n\n\ndef run_screener_shared() -> None:\n    """Draait de gedeelde screener 1x -- de resultaten zijn voor iedereen zichtbaar."""\n    print("=== Gedeelde screener draaien (publiek, voor iedereen zichtbaar) ===")\n    screener.main()\n\n\ndef run_screener_emails(preferences: dict) -> None:\n    """Stuurt de screener-mail naar gebruikers die zich daar expliciet voor hebben aangemeld."""\n    print("\\n=== Screener-mails versturen aan opt-in-gebruikers ===")\n    opted_in = [email for email, prefs in preferences.items() if prefs.get("wants_screener_email")]\n    print(f"{len(opted_in)} gebruiker(s) willen de screener-mail ontvangen.")\n\n    if not opted_in:\n        return\n\n    if not os.path.exists("supertrend_signals.csv"):\n        print("Geen supertrend_signals.csv gevonden -- kan geen screener-mail versturen.")\n        return\n\n    df_hits = pd.read_csv("supertrend_signals.csv")\n    if df_hits.empty:\n        print("Geen signalen deze week -- geen screener-mail nodig.")\n        return\n\n    text_body, html_body = screener.build_email_body(df_hits)\n    subject = f"Supertrend-screener: {len(df_hits)} nieuwe signalen"\n\n    for user_email in opted_in:\n        send_email(subject=subject, body_text=text_body, body_html=html_body, to_email=user_email)\n\n\ndef run_portfolio_emails(preferences: dict) -> None:\n    """\n    Checkt en mailt elke geregistreerde gebruiker zijn eigen, persoonlijke\n    portfolio -- behalve als hij dat expliciet heeft uitgezet. Standaard AAN\n    (ook voor gebruikers die nog nooit hun voorkeuren hebben aangepast).\n    """\n    print("\\n=== Persoonlijke portfolio-e-mails versturen ===")\n    users = get_all_users_with_holdings()\n    print(f"{len(users)} gebruiker(s) gevonden met een portfolio.")\n\n    for user_email, holdings in users.items():\n        user_prefs = preferences.get(user_email, {})\n        if not user_prefs.get("wants_portfolio_email", True):\n            print(f"\\n--- {user_email}: heeft de portfolio-mail uitgezet, overgeslagen ---")\n            continue\n\n        print(f"\\n--- {user_email} ({len(holdings)} positie(s)) ---")\n        results = []\n        for holding in holdings:\n            result = check_holding(holding["naam"], holding["ticker"])\n            if result:\n                results.append(result)\n\n        if not results:\n            print("  Geen van de posities kon gecheckt worden -- geen mail verstuurd.")\n            continue\n\n        df = pd.DataFrame(results)\n        text_body, html_body = build_email_body(df)\n        n_changed = int(df["recent_gewijzigd"].sum())\n        subject = (\n            f"Portfolio Watch: {n_changed} wijziging(en)"\n            if n_changed > 0 else "Portfolio Watch: geen wijzigingen"\n        )\n\n        send_email(subject=subject, body_text=text_body, body_html=html_body, to_email=user_email)\n\n\nif __name__ == "__main__":\n    run_screener_shared()\n    all_preferences = get_all_preferences()\n    run_screener_emails(all_preferences)\n    run_portfolio_emails(all_preferences)\n    print("\\nKlaar.")\n',
    'supabase_schema.sql': '-- Plak dit in Supabase\'s SQL Editor (linkermenu) en klik "Run"\n--\n-- LET OP over beveiliging: we gebruiken Google-login via Streamlit, niet\n-- via Supabase\'s eigen inlogsysteem. Daarom kunnen we Supabase\'s\n-- rij-beveiliging (Row Level Security) hier niet automatisch aan Google-\n-- identiteit koppelen. In plaats daarvan filtert onze Python-code (die\n-- ALTIJD server-side draait, nooit zichtbaar voor de browser van de\n-- gebruiker) bij elke query expliciet op de ingelogde gebruiker. Dat is\n-- voor dit schaalniveau een veilige, gangbare aanpak.\n\ncreate table portfolio_holdings (\n    id bigint generated always as identity primary key,\n    user_email text not null,\n    naam text not null,\n    ticker text not null,\n    created_at timestamp with time zone default now()\n);\n\n-- Index om snel te filteren op e-mailadres\ncreate index idx_portfolio_holdings_user_email on portfolio_holdings (user_email);\n\n-- E-mail-voorkeuren per gebruiker (opt-in voor de wekelijkse screener-mail\n-- en/of de persoonlijke portfolio-mail)\ncreate table user_preferences (\n    user_email text primary key,\n    wants_screener_email boolean not null default false,\n    wants_portfolio_email boolean not null default true,\n    updated_at timestamp with time zone default now()\n);\n',
    '.streamlit/config.toml': '[theme]\nbase = "dark"\nprimaryColor = "#1FAE96"\nbackgroundColor = "#101825"\nsecondaryBackgroundColor = "#1B2536"\ntextColor = "#EAEDF1"\nfont = "sans serif"\n',
}

for relative_path, content in FILES.items():
    directory = os.path.dirname(relative_path)
    if directory and not os.path.isdir(directory):
        os.makedirs(directory, exist_ok=True)
    with open(relative_path, "w", encoding="utf-8") as f:
        f.write(content)
    print(f"Weggeschreven: {relative_path} ({len(content)} tekens)")

print("\nVOLGENDE STAPPEN:")
print("1. Draai supabase_schema.sql (opnieuw) in Supabase's SQL Editor")
print("   -- dit voegt de nieuwe 'user_preferences'-tabel toe")
print("2. git add . && git commit -m 'Voorkeuren + styling' && git push")
print("   -- dit werkt zowel je live Streamlit-app als de GitHub Action bij")
print("3. Test lokaal: streamlit run dashboard.py")
